import nacl from "tweetnacl";
import { decodeBase64, encodeBase64 } from "tweetnacl-util";

export interface JettAuthClaims {
  iss: string;
  sub: string; // "sol:<wallet_pubkey>"
  aud: string;
  exp: number;
  iat: number;
  x_id?: string;
  x_handle?: string;
  x_verified?: boolean;
  wallets: string[];
  auth_methods: ("x_oauth" | "solana_sign")[];
}

const HEADER = { alg: "EdDSA", typ: "JWT" };

function base64UrlEncode(data: Uint8Array | string): string {
  const str = typeof data === "string" ? data : encodeBase64(data);
  return str.replace(/\+/g, "-").replace(/\//g, "_").replace(/=+$/, "");
}

function base64UrlDecode(str: string): Uint8Array {
  const padded = str.replace(/-/g, "+").replace(/_/g, "/");
  return decodeBase64(padded + "=".repeat((4 - (padded.length % 4)) % 4));
}

function encodeJSON(obj: unknown): string {
  return base64UrlEncode(new TextEncoder().encode(JSON.stringify(obj)));
}

function decodeJSON<T>(encoded: string): T {
  return JSON.parse(new TextDecoder().decode(base64UrlDecode(encoded)));
}

export function signJWT(
  claims: JettAuthClaims,
  privateKey: Uint8Array
): string {
  const header = encodeJSON(HEADER);
  const payload = encodeJSON(claims);
  const message = new TextEncoder().encode(`${header}.${payload}`);
  const signature = nacl.sign.detached(message, privateKey);
  return `${header}.${payload}.${base64UrlEncode(signature)}`;
}

export function verifyJWT(
  token: string,
  publicKey: Uint8Array
): JettAuthClaims {
  const parts = token.split(".");
  if (parts.length !== 3) throw new Error("Invalid JWT format");

  const [header, payload, sig] = parts;
  const message = new TextEncoder().encode(`${header}.${payload}`);
  const signature = base64UrlDecode(sig);

  if (!nacl.sign.detached.verify(message, signature, publicKey)) {
    throw new Error("Invalid JWT signature");
  }

  const decoded = decodeJSON<{ alg: string }>(header);
  if (decoded.alg !== "EdDSA") throw new Error(`Unsupported alg: ${decoded.alg}`);

  const claims = decodeJSON<JettAuthClaims>(payload);

  if (claims.exp && claims.exp < Math.floor(Date.now() / 1000)) {
    throw new Error("JWT expired");
  }

  return claims;
}

export function generateKeyPair(): { publicKey: Uint8Array; privateKey: Uint8Array } {
  const kp = nacl.sign.keyPair();
  return { publicKey: kp.publicKey, privateKey: kp.secretKey };
}

export function createClaims(opts: {
  walletPubkey: string;
  wallets?: string[];
  xId?: string;
  xHandle?: string;
  xVerified?: boolean;
  authMethods: ("x_oauth" | "solana_sign")[];
  expiresInSeconds?: number;
}): JettAuthClaims {
  const now = Math.floor(Date.now() / 1000);
  return {
    iss: "https://jettoptics.ai",
    sub: `sol:${opts.walletPubkey}`,
    aud: "jettchat",
    iat: now,
    exp: now + (opts.expiresInSeconds ?? 86400), // default 24h
    x_id: opts.xId,
    x_handle: opts.xHandle,
    x_verified: opts.xVerified,
    wallets: opts.wallets ?? [opts.walletPubkey],
    auth_methods: opts.authMethods,
  };
}
