import { verifyJWT, signJWT, type JettAuthClaims } from "../src/jwt";
import { extractToken, buildSessionCookie } from "../src/session";

export function createRefreshHandler(
  jwtPrivateKey: Uint8Array,
  jwtPublicKey: Uint8Array
) {
  return async (request: Request): Promise<Response> => {
    const cookieHeader = request.headers.get("cookie");
    const token = extractToken(cookieHeader);

    if (!token) {
      return Response.json({ error: "No session" }, { status: 401 });
    }

    let claims: JettAuthClaims;
    try {
      // Allow expired tokens for refresh (re-verify signature only)
      claims = verifyJWTIgnoreExpiry(token, jwtPublicKey);
    } catch {
      return Response.json({ error: "Invalid session" }, { status: 401 });
    }

    // Issue fresh JWT with same claims, new exp
    const now = Math.floor(Date.now() / 1000);
    const refreshedClaims: JettAuthClaims = {
      ...claims,
      iat: now,
      exp: now + 86400, // 24h
    };

    const jwt = signJWT(refreshedClaims, jwtPrivateKey);
    const cookie = buildSessionCookie(jwt);

    return new Response(
      JSON.stringify({ success: true, claims: refreshedClaims }),
      {
        status: 200,
        headers: {
          "Content-Type": "application/json",
          "Set-Cookie": cookie,
        },
      }
    );
  };
}

// Verify JWT signature without checking expiry (for refresh flow)
function verifyJWTIgnoreExpiry(
  token: string,
  publicKey: Uint8Array
): JettAuthClaims {
  // Temporarily set exp far in the future to bypass expiry check
  const parts = token.split(".");
  if (parts.length !== 3) throw new Error("Invalid JWT");

  // Decode payload, override exp, re-encode, verify, then return original claims
  const payloadJson = JSON.parse(
    Buffer.from(parts[1].replace(/-/g, "+").replace(/_/g, "/"), "base64").toString()
  );
  const originalExp = payloadJson.exp;
  payloadJson.exp = Math.floor(Date.now() / 1000) + 3600;

  // We still need to verify the ORIGINAL token's signature
  const { verifyJWT: verify } = require("../src/jwt");

  // Just verify signature on the original token by catching only expiry errors
  try {
    return verify(token, publicKey);
  } catch (e: any) {
    if (e.message === "JWT expired") {
      // Signature was valid, just expired — return the decoded claims
      return { ...payloadJson, exp: originalExp };
    }
    throw e;
  }
}
