import {
  exchangeCodeForTokens,
  fetchXProfile,
  type XOAuthConfig,
  type XOAuthTokens,
} from "../src/x-oauth";
import { signJWT, createClaims, type JettAuthClaims } from "../src/jwt";
import { buildSessionCookie } from "../src/session";
import { getPKCEVerifier } from "./x-auth";

export interface XCallbackResult {
  tokens: XOAuthTokens;
  claims: JettAuthClaims;
  jwt: string;
  cookie: string;
}

export function createXCallbackHandler(
  config: XOAuthConfig,
  jwtPrivateKey: Uint8Array,
  opts?: {
    onTokens?: (
      walletPubkey: string | null,
      tokens: XOAuthTokens
    ) => Promise<void>;
  }
) {
  return async (request: Request): Promise<Response> => {
    const url = new URL(request.url);
    const code = url.searchParams.get("code");
    const state = url.searchParams.get("state");

    if (!code || !state) {
      return Response.json(
        { error: "Missing code or state" },
        { status: 400 }
      );
    }

    // Retrieve and validate PKCE verifier
    const codeVerifier = getPKCEVerifier(state);
    if (!codeVerifier) {
      return Response.json(
        { error: "Invalid or expired state" },
        { status: 400 }
      );
    }

    // Exchange code for tokens
    const tokens = await exchangeCodeForTokens(config, code, codeVerifier);

    // Fetch X profile
    const xProfile = await fetchXProfile(tokens.access_token);

    // Create JWT claims (wallet will be linked later via Solana signMessage)
    const claims = createClaims({
      walletPubkey: "pending", // No wallet yet — X-only auth
      wallets: [],
      xId: xProfile.id,
      xHandle: xProfile.username,
      xVerified: xProfile.verified,
      authMethods: ["x_oauth"],
    });

    const jwt = signJWT(claims, jwtPrivateKey);
    const cookie = buildSessionCookie(jwt);

    // Store tokens if callback provided
    if (opts?.onTokens) {
      await opts.onTokens(null, tokens);
    }

    return new Response(null, {
      status: 302,
      headers: {
        Location: "/?x_connected=true",
        "Set-Cookie": cookie,
      },
    });
  };
}
