import { generatePKCE, buildAuthorizeUrl, type XOAuthConfig } from "../src/x-oauth";

// In-memory PKCE store (replace with Redis/SpacetimeDB in production)
const pkceStore = new Map<string, { codeVerifier: string; expiresAt: number }>();

export function createXAuthHandler(config: XOAuthConfig) {
  return async () => {
    const pkce = generatePKCE();

    // Store PKCE verifier keyed by state (5 min TTL)
    pkceStore.set(pkce.state, {
      codeVerifier: pkce.codeVerifier,
      expiresAt: Date.now() + 300_000,
    });

    // Cleanup expired entries
    for (const [key, val] of pkceStore) {
      if (val.expiresAt < Date.now()) pkceStore.delete(key);
    }

    const url = buildAuthorizeUrl(config, pkce);
    return Response.redirect(url);
  };
}

export function getPKCEVerifier(state: string): string | null {
  const entry = pkceStore.get(state);
  if (!entry || entry.expiresAt < Date.now()) {
    pkceStore.delete(state);
    return null;
  }
  pkceStore.delete(state); // One-time use
  return entry.codeVerifier;
}

export { pkceStore };
