import nacl from "tweetnacl";
import { decodeBase64, encodeUTF8 } from "tweetnacl-util";

export interface NonceChallenge {
  nonce: string;
  message: string;
  issuedAt: number;
  expiresAt: number;
}

export interface VerifyResult {
  valid: boolean;
  walletPubkey: string;
}

const NONCE_TTL_SECONDS = 300; // 5 minutes

export function createNonceChallenge(walletPubkey: string): NonceChallenge {
  const nonce = Array.from(nacl.randomBytes(32))
    .map((b) => b.toString(16).padStart(2, "0"))
    .join("");
  const issuedAt = Math.floor(Date.now() / 1000);
  const expiresAt = issuedAt + NONCE_TTL_SECONDS;
  const message = [
    "JettChat Authentication",
    "",
    `Wallet: ${walletPubkey}`,
    `Nonce: ${nonce}`,
    `Issued: ${new Date(issuedAt * 1000).toISOString()}`,
    "",
    "Sign this message to verify wallet ownership.",
    "This will not trigger a blockchain transaction.",
  ].join("\n");

  return { nonce, message, issuedAt, expiresAt };
}

export function verifySignedMessage(
  message: string,
  signatureBase64: string,
  walletPubkeyBase58: string
): VerifyResult {
  try {
    const messageBytes = new TextEncoder().encode(message);
    const signatureBytes = decodeBase64(signatureBase64);
    const pubkeyBytes = base58Decode(walletPubkeyBase58);

    const valid = nacl.sign.detached.verify(
      messageBytes,
      signatureBytes,
      pubkeyBytes
    );

    return { valid, walletPubkey: walletPubkeyBase58 };
  } catch {
    return { valid: false, walletPubkey: walletPubkeyBase58 };
  }
}

export function isNonceExpired(challenge: NonceChallenge): boolean {
  return Math.floor(Date.now() / 1000) > challenge.expiresAt;
}

// Minimal Base58 decoder (Solana pubkeys are Base58-encoded)
const BASE58_ALPHABET = "123456789ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz";

function base58Decode(str: string): Uint8Array {
  const bytes: number[] = [0];
  for (const char of str) {
    const idx = BASE58_ALPHABET.indexOf(char);
    if (idx === -1) throw new Error(`Invalid Base58 character: ${char}`);
    let carry = idx;
    for (let j = 0; j < bytes.length; j++) {
      carry += bytes[j] * 58;
      bytes[j] = carry & 0xff;
      carry >>= 8;
    }
    while (carry > 0) {
      bytes.push(carry & 0xff);
      carry >>= 8;
    }
  }
  // Leading zeros
  for (const char of str) {
    if (char !== "1") break;
    bytes.push(0);
  }
  return new Uint8Array(bytes.reverse());
}
