import { verifySignedMessage, isNonceExpired, createNonceChallenge, type NonceChallenge } from "../src/solana-auth";
import { signJWT, createClaims, verifyJWT, type JettAuthClaims } from "../src/jwt";
import { buildSessionCookie, extractToken } from "../src/session";

// In-memory nonce store (replace with SpacetimeDB in production)
const nonceStore = new Map<string, NonceChallenge>();

export function createWalletChallengeHandler() {
  return async (request: Request): Promise<Response> => {
    const url = new URL(request.url);
    const pubkey = url.searchParams.get("pubkey");

    if (!pubkey) {
      return Response.json({ error: "Missing pubkey" }, { status: 400 });
    }

    const challenge = createNonceChallenge(pubkey);
    nonceStore.set(challenge.nonce, challenge);

    // Cleanup expired nonces
    for (const [key, val] of nonceStore) {
      if (isNonceExpired(val)) nonceStore.delete(key);
    }

    return Response.json({
      message: challenge.message,
      nonce: challenge.nonce,
    });
  };
}

export function createWalletVerifyHandler(jwtPrivateKey: Uint8Array, jwtPublicKey: Uint8Array) {
  return async (request: Request): Promise<Response> => {
    const body = await request.json();
    const { message, signature, publicKey, nonce } = body;

    if (!message || !signature || !publicKey || !nonce) {
      return Response.json(
        { error: "Missing required fields" },
        { status: 400 }
      );
    }

    // Validate nonce
    const challenge = nonceStore.get(nonce);
    if (!challenge) {
      return Response.json(
        { error: "Invalid or expired nonce" },
        { status: 400 }
      );
    }
    if (isNonceExpired(challenge)) {
      nonceStore.delete(nonce);
      return Response.json({ error: "Nonce expired" }, { status: 400 });
    }
    nonceStore.delete(nonce); // One-time use

    // Verify signature
    const result = verifySignedMessage(message, signature, publicKey);
    if (!result.valid) {
      return Response.json(
        { error: "Invalid signature" },
        { status: 401 }
      );
    }

    // Check if user already has an X-only session (link wallet to it)
    const cookieHeader = request.headers.get("cookie");
    const existingToken = extractToken(cookieHeader);
    let existingClaims: JettAuthClaims | null = null;

    if (existingToken) {
      try {
        existingClaims = verifyJWT(existingToken, jwtPublicKey);
      } catch {
        // Expired or invalid — start fresh
      }
    }

    // Build claims: merge X info if present, add wallet
    const claims = createClaims({
      walletPubkey: publicKey,
      wallets: [publicKey],
      xId: existingClaims?.x_id,
      xHandle: existingClaims?.x_handle,
      xVerified: existingClaims?.x_verified,
      authMethods: existingClaims?.x_id
        ? ["x_oauth", "solana_sign"]
        : ["solana_sign"],
    });

    const jwt = signJWT(claims, jwtPrivateKey);
    const cookie = buildSessionCookie(jwt);

    return new Response(
      JSON.stringify({ success: true, claims }),
      {
        status: 200,
        headers: {
          "Content-Type": "application/json",
          "Set-Cookie": cookie,
        },
      }
    );
  };
}
